                    <h2 id="endpoints-POSTapi-v1-vacancies--vacancy_id--transition">POST api/v1/vacancies/{vacancy_id}/transition</h2>

<p>
</p>



<span id="example-requests-POSTapi-v1-vacancies--vacancy_id--transition">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request POST \
    "https://develop.backend-v1.humae.com.mx/api/v1/vacancies/16/transition" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json" \
    --data "{
    \"to\": \"architecto\",
    \"reason\": \"n\"
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "https://develop.backend-v1.humae.com.mx/api/v1/vacancies/16/transition"
);

const headers = {
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "to": "architecto",
    "reason": "n"
};

fetch(url, {
    method: "POST",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>

</span>

